import{_ as e,o as s,c as i,ag as l}from"./chunks/framework.CAXxHpAX.js";const k=JSON.parse('{"title":"Windows 平台安装 Node.js","description":"","frontmatter":{},"headers":[],"relativePath":"node/windows.md","filePath":"node/windows.md"}'),o={name:"node/windows.md"};function t(n,a,h,d,r,p){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="windows-平台安装-node-js" tabindex="-1">Windows 平台安装 Node.js <a class="header-anchor" href="#windows-平台安装-node-js" aria-label="Permalink to &quot;Windows 平台安装 Node.js&quot;">​</a></h1><p>三大 AI 编程工具的必备运行环境</p><div class="tip custom-block"><p class="custom-block-title">💡 重要说明</p><p>Claude Code、CodeX 和 Gemini CLI 都需要 Node.js 18+ 运行环境。 如果您已安装 Node.js 18 或更高版本，可跳过本章节。 验证命令：<code>node -v</code></p></div><h2 id="方法一-官方安装包-推荐" tabindex="-1">方法一：官方安装包（推荐） <a class="header-anchor" href="#方法一-官方安装包-推荐" aria-label="Permalink to &quot;方法一：官方安装包（推荐）&quot;">​</a></h2><ol><li>访问 Node.js 官网： <a href="https://nodejs.org/zh-cn/download" target="_blank" rel="noreferrer">https://nodejs.org/zh-cn/download</a></li><li>下载 LTS（长期支持）版本的 Windows Installer (.msi)</li><li>运行安装包，采用默认配置完成安装</li><li>安装程序会自动配置系统 PATH 环境变量</li></ol><h2 id="方法二-包管理器安装" tabindex="-1">方法二：包管理器安装 <a class="header-anchor" href="#方法二-包管理器安装" aria-label="Permalink to &quot;方法二：包管理器安装&quot;">​</a></h2><h3 id="使用-winget" tabindex="-1">使用 Winget <a class="header-anchor" href="#使用-winget" aria-label="Permalink to &quot;使用 Winget&quot;">​</a></h3><p>Windows 11 或 Windows 10 最新版：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install OpenJS.NodeJS.LTS</span></span></code></pre></div><h3 id="使用-chocolatey" tabindex="-1">使用 Chocolatey <a class="header-anchor" href="#使用-chocolatey" aria-label="Permalink to &quot;使用 Chocolatey&quot;">​</a></h3><p>需先安装 Chocolatey：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">choco install nodejs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lts</span></span></code></pre></div><h3 id="使用-scoop" tabindex="-1">使用 Scoop <a class="header-anchor" href="#使用-scoop" aria-label="Permalink to &quot;使用 Scoop&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scoop install nodejs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lts</span></span></code></pre></div><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>打开命令提示符或 PowerShell，执行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span></code></pre></div><p>如果显示版本号（如 v18.x.x 或更高），说明安装成功。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示-不是内部或外部命令" tabindex="-1">提示&quot;不是内部或外部命令&quot; <a class="header-anchor" href="#提示-不是内部或外部命令" aria-label="Permalink to &quot;提示&quot;不是内部或外部命令&quot;&quot;">​</a></h3><ul><li>重新打开终端窗口</li><li>检查 PATH 环境变量是否包含 Node.js 路径</li><li>重启电脑后再试</li></ul><h3 id="安装失败" tabindex="-1">安装失败 <a class="header-anchor" href="#安装失败" aria-label="Permalink to &quot;安装失败&quot;">​</a></h3><ul><li>以管理员身份运行安装程序</li><li>关闭杀毒软件后重试</li><li>检查系统盘空间是否充足</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">✅ 环境准备完成！</p><p>现在您可以继续安装 Claude Code、CodeX 或 Gemini CLI 了。</p></div><ul><li><a href="/node/windows">返回环境安装总览</a></li><li><a href="/deploy/claude-code">安装 Claude Code</a></li><li><a href="/tools/cc-switch">使用 CC-Switch 工具</a></li></ul>`,26)])])}const u=e(o,[["render",t]]);export{k as __pageData,u as default};
